  `payload_ia` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`payload_ia`)),
  `criado_em` datetime NOT NULL DEFAULT current_timestamp(),
