CREATE ALGORITHM=UNDEFINED DEFINER=`u308598921_via_ccm`@`127.0.0.1` SQL SECURITY DEFINER VIEW `bi_alertas_financeiros`  AS SELECT 'recebimento_vencido' AS `tipo_alerta`, `r`.`id_recebimento` AS `id_origem`, `r`.`id_cliente` AS `id_cliente`, `r`.`id_contrato` AS `id_contrato`, `r`.`numero_contrato` AS `numero_contrato`, `r`.`competencia` AS `competencia`, `r`.`valor_inadimplente` AS `valor_impacto`, `r`.`dias_atraso` AS `dias_atraso`, CASE WHEN `r`.`dias_atraso` >= 15 THEN 'alta' WHEN `r`.`dias_atraso` >= 7 THEN 'media' ELSE 'baixa' END AS `prioridade`, concat('Recebimento vencido ha ',`r`.`dias_atraso`,' dias com saldo de R$ ',format(`r`.`valor_inadimplente`,2)) AS `sugestao` FROM `bi_fato_recebimentos` AS `r` WHERE `r`.`valor_inadimplente` > 0union allselect 'contrato_sem_provisionamento' AS `tipo_alerta`,`dc`.`id_contrato` AS `id_origem`,`dc`.`id_cliente` AS `id_cliente`,`dc`.`id_contrato` AS `id_contrato`,`dc`.`numero_contrato` AS `numero_contrato`,NULL AS `competencia`,`dc`.`valor_liquido_mensal` AS `valor_impacto`,0 AS `dias_atraso`,'media' AS `prioridade`,concat('Contrato ',`dc`.`numero_contrato`,' esta ativo, mas o provisionamento esta como ',`dc`.`status_provisionamento`) AS `sugestao` from `bi_dim_contratos` `dc` where `dc`.`status_contrato` = 'ativo' and coalesce(`dc`.`status_provisionamento`,'') <> 'provisionado' union all select 'servidor_com_risco' AS `tipo_alerta`,`dc`.`id_servidor` AS `id_origem`,`dc`.`id_cliente` AS `id_cliente`,`dc`.`id_contrato` AS `id_contrato`,`dc`.`numero_contrato` AS `numero_contrato`,NULL AS `competencia`,`dc`.`valor_liquido_mensal` AS `valor_impacto`,0 AS `dias_atraso`,'media' AS `prioridade`,concat('Servidor ',coalesce(`dc`.`servidor_nome`,'sem nome'),' esta com status ',coalesce(`dc`.`servidor_status_conexao`,'indefinido')) AS `sugestao` from `bi_dim_contratos` `dc` where `dc`.`status_contrato` = 'ativo' and coalesce(`dc`.`servidor_status_conexao`,'') <> 'conectado'  ;

