case when `cc`.`amortizar` = 1 and timestampdiff(MONTH,str_to_date(date_format(`cc`.`data_lancamento`,'%Y-%m-01'),'%Y-%m-%d'),str_to_date(date_format(curdate(),'%Y-%m-01'),'%Y-%m-%d')) between 0 and greatest(`cc`.`meses_amortizacao`,1) - 1 then greatest(`cc`.`valor_custo` - `cc`.`valor_cobrado_cliente`,0) / greatest(`cc`.`meses_amortizacao`,1) when `cc`.`amortizar` = 0 and date_format(`cc`.`data_lancamento`,'%Y-%m') = date_format(curdate(),'%Y-%m') then greatest(`cc`.`valor_custo` - `cc`.`valor_cobrado_cliente`,0) else 0 end else 0 end) AS `custo_pontual_rateado_mes_atual`,sum(case when `cc`.`status` = 'ativo' and `cc`.`recorrencia` = 'unico' and `cc`.`entra_payback` = 1 then case when `cc`.`amortizar` = 1 then greatest(`cc`.`valor_custo` - `cc`.`valor_cobrado_cliente`,0) / greatest(`cc`.`meses_amortizacao`,1) * least(greatest(timestampdiff(MONTH,str_to_date(date_format(`cc`.`data_lancamento`,'%Y-%m-01'),'%Y-%m-%d'),str_to_date(date_format(curdate(),'%Y-%m-01'),'%Y-%m-%d')) + 1,0),greatest(`cc`.`meses_amortizacao`,1)) when `cc`.`data_lancamento` <= curdate() then greatest(`cc`.`valor_custo` - `cc`.`valor_cobrado_cliente`,0) else 0 end else 0 end) AS `payback_pago_estimado` from `contrato_custos` `cc` where `cc`.`status` = 'ativo' group by `cc`.`id_empresa`,`cc`.`id_contrato`) `custos` on(`custos`.`id_empresa` = `dc`.`id_empresa` and `custos`.`id_contrato` = `dc`.`id_contrato`))) `base` left join (select `r`.`id_empresa` AS `id_empresa`,`r`.`id_contrato` AS `id_contrato`,sum(case when `r`.`status` <> 'excluido' then `r`.`valor_final` else 0 end) AS `receita_prevista_acumulada`,sum(case when `r`.`status` <> 'excluido' then `r`.`valor_recebido` else 0 end) AS `receita_recebida_acumulada`,sum(case when `r`.`status` in ('aberto','gerado','parcial','vencido') then `r`.`saldo_restante` else 0 end) AS `valor_em_aberto`,sum(case when `r`.`status` in ('aberto','gerado','parcial','vencido') and `r`.`saldo_restante` > 0 and `r`.`data_vencimento` < curdate() then `r`.`saldo_restante` else 0 end) AS `valor_vencido`,count(distinct `r`.`competencia`) AS `meses_base` from `recebimentos` `r` group by `r`.`id_empresa`,`r`.`id_contrato`) `fin` on(`fin`.`id_empresa` = `base`.`id_empresa` and `fin`.`id_contrato` = `base`.`id_contrato`)) ;

