oalesce(`custos_lancados`.`custo_equipamento_lancado_total`,0) AS `custo_equipamento_lancado_total`, coalesce(`custos_lancados`.`custo_recorrente_cliente_mensal`,0) AS `custo_recorrente_cliente_mensal`, coalesce(`custos_lancados`.`custo_manutencao_total`,0) AS `custo_manutencao_total`, coalesce(`custos_lancados`.`custo_amortizado_mensal_base`,0) AS `custo_amortizado_mensal_base`, coalesce(`custos_lancados`.`custo_empresa_liquido_total`,0) AS `custo_empresa_liquido_total`, coalesce(`custos_lancados`.`investimento_lancado_total`,0) AS `investimento_lancado_total` FROM (((((`contratos` `ct` left join `clientes` `cli` on(`cli`.`id` = `ct`.`id_cliente`)) left join `planos` `pl` on(`pl`.`id` = `ct`.`id_plano`)) left join `servidores` `srv` on(`srv`.`id` = `ct`.`id_servidor`)) left join `bi_contrato_custos_operacionais` `custos` on(`custos`.`id_contrato` = `ct`.`id`)) left join `bi_contrato_custos_lancados` `custos_lancados` on(`custos_lancados`.`id_contrato` = `ct`.`id`)) WHERE coalesce(`ct`.`status_contrato`,'') <> 'excluido' ;

