o` else 0 end) AS `receita_recebida_acumulada`,sum(case when `r`.`status` in ('aberto','gerado','parcial','vencido') then `r`.`saldo_restante` else 0 end) AS `valor_em_aberto`,sum(case when `r`.`status` in ('aberto','gerado','parcial','vencido') and `r`.`saldo_restante` > 0 and `r`.`data_vencimento` < curdate() then `r`.`saldo_restante` else 0 end) AS `valor_vencido`,count(distinct `r`.`competencia`) AS `meses_base` from `recebimentos` `r` group by `r`.`id_contrato`) `fin` on(`fin`.`id_contrato` = `dc`.`id_contrato`)) ;

